noncompliant:
// In file1.h
#define MAX_SIZE 1024

// In file2.c (different file)
#include "file1.h"
#undef MAX_SIZE  // Noncompliant: undefining from another file
#define MAX_SIZE 2048

// Undefining system or library macros
#include <stdio.h>
#undef NULL      // Noncompliant: affects global scope
#define NULL ((void*)0)

compliant:
// Limited scope macro usage in same file
#define TEMP_MACRO(x) do { \
    printf("Processing: %d\n", x); \
    process(x); \
} while(0)

// Use it a few times
TEMP_MACRO(1);
TEMP_MACRO(2);
TEMP_MACRO(3);

#undef TEMP_MACRO  // OK: limited scope, same file

// Conditional compilation with cleanup
#ifdef DEBUG_MODE
    #define DBG_PRINT(x) printf(x)
#else
    #define DBG_PRINT(x)
#endif

// Use debug macro
DBG_PRINT("Debug info");

// Clean up at end of same file
#undef DBG_PRINT
